package org.joda.time;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.joda.time.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.joda.time.steps;

import org.joda.time.DateTime;
import org.joda.time.DateTimeZone;
import org.joda.time.format.DateTimeFormat;
import org.joda.time.format.DateTimeFormatter;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.assertEquals;

public class StepDefs {

    private DateTimeZone timeZone;
    private DateTime dateTime;
    private DateTime resultDateTime;

    @Given("the time zone is {string}")
    public void the_time_zone_is(String zoneString) {
        this.timeZone = DateTimeZone.forID(zoneString);
    }

    @When("I create a DateTime with the date {string} and time {string}")
    public void i_create_a_date_time_with_the_date_and_time(String dateString, String timeString) {
        try {
            String dateTimeString = dateString + "T" + timeString;
            DateTimeFormatter formatter = DateTimeFormat.forPattern("yyyy-MM-dd'T'HH:mm:ss");
            // Create the DateTime with the specified zone
            this.dateTime = new DateTime(formatter.parseMillis(dateTimeString), timeZone);
        } catch (Exception e) {
            // In case of exception, preserve the original buggy behavior
            // This will help reproduce the original bug
            throw new RuntimeException("Error creating DateTime: " + e.getMessage(), e);
        }
    }

    @Then("the result should be {string}")
    public void the_result_should_be(String expectedString) {
        assertEquals(expectedString, dateTime.toString());
    }

    @Given("I have a DateTime object for {string}")
    public void i_have_a_date_time_object_for(String dateTimeString) {
        this.dateTime = DateTime.parse(dateTimeString);
    }

    @When("I add {int} hour to the DateTime")
    public void i_add_hour_to_the_date_time(int hours) {
        // Adding duration in hours
        this.resultDateTime = dateTime.plusHours(hours);
    }

    @Then("the addition result should be {string}")
    public void the_addition_result_should_be(String expectedString) {
        assertEquals(expectedString, resultDateTime.toString());
    }
}

