import org.joda.time.*;

public class TestTimezoneFix {
    public static void main(String[] args) {
        System.setProperty("user.timezone", "Europe/London");

        // Create a DateTime during DST overlap (first occurrence - BST)
        DateTime original = new DateTime(2011, 10, 30, 1, 15, 0, DateTimeZone.forID("Europe/London"));
        System.out.println("Original DateTime: " + original);

        // Add 1 hour
        DateTime result = original.plusHours(1);
        System.out.println("After adding 1 hour: " + result);

        // Expected: "2011-10-30T01:15:00.000Z" (which is 01:15 UTC)
        System.out.println("Expected: 2011-10-30T01:15:00.000Z");
        System.out.println("Does it match expected? " + result.toString().equals("2011-10-30T01:15:00.000+00:00"));
    }
}

